content:
{
  "sentences": [
    {
      "text": "請你把這本書帶來學校。",
      "pinyin": "Qǐng nǐ bǎ zhè běn shū dài lái xuéxiào.",
      "pinyin_numeric": "qing3 ni3 ba3 zhe4 ben3 shu1 dai4 lai2 xue2xiao4.",
      "translation_en": "Please bring this book to school.",
      "translation_ko": "이 책을 학교로 가져와 주세요."
    },
    {
      "text": "他把手機帶去公司了。",
      "pinyin": "Tā bǎ shǒujī dài qù gōngsī le.",
      "pinyin_numeric": "ta1 ba3 shou3ji1 dai4 qu4 gong1si1 le0.",
      "translation_en": "He took his phone to the company.",
      "translation_ko": "그는 핸드폰을 회사로 가져갔어요."
    },
    {
      "text": "我媽媽把水果帶來我家。",
      "pinyin": "Wǒ māma bǎ shuǐguǒ dài lái wǒ jiā.",
      "pinyin_numeric": "wo3 ma1ma ba3 shui3guo3 dai4 lai2 wo3 jia1.",
      "translation_en": "My mom brought fruit to my house.",
      "translation_ko": "우리 엄마가 과일을 우리 집으로 가져왔어요."
    },
    {
      "text": "請你把那杯咖啡帶去辦公室。",
      "pinyin": "Qǐng nǐ bǎ nà bēi kāfēi dài qù bàngōngshì.",
      "pinyin_numeric": "qing3 ni3 ba3 na4 bei1 ka1fei1 dai4 qu4 ban4gong1shi4.",
      "translation_en": "Please take that cup of coffee to the office.",
      "translation_ko": "그 커피 한 잔을 사무실로 가져가 주세요."
    },
    {
      "text": "他把我的書帶來圖書館了。",
      "pinyin": "Tā bǎ wǒ de shū dài lái túshūguǎn le.",
      "pinyin_numeric": "ta1 ba3 wo3 de0 shu1 dai4 lai2 tu2shu1guan3 le0.",
      "translation_en": "He brought my book to the library.",
      "translation_ko": "그가 제 책을 도서관으로 가져왔어요."
    },
    {
      "text": "妹妹把她的貓帶去公園。",
      "pinyin": "Mèimei bǎ tā de māo dài qù gōngyuán.",
      "pinyin_numeric": "mei4mei ba3 ta1 de0 mao1 dai4 qu4 gong1yuan2.",
      "translation_en": "My younger sister took her cat to the park.",
      "translation_ko": "여동생이 자기 고양이를 공원으로 데려갔어요."
    },
    {
      "text": "請你把這個袋子帶來餐廳。",
      "pinyin": "Qǐng nǐ bǎ zhège dàizi dài lái cāntīng.",
      "pinyin_numeric": "qing3 ni3 ba3 zhe4ge dai4zi dai4 lai2 can1ting1.",
      "translation_en": "Please bring this bag to the restaurant.",
      "translation_ko": "이 가방을 식당으로 가져와 주세요."
    },
    {
      "text": "他把那本雜誌帶去醫院了。",
      "pinyin": "Tā bǎ nà běn zázhì dài qù yīyuàn le.",
      "pinyin_numeric": "ta1 ba3 na4 ben3 za2zhi4 dai4 qu4 yi1yuan4 le0.",
      "translation_en": "He took that magazine to the hospital.",
      "translation_ko": "그는 그 잡지를 병원으로 가져갔어요."
    },
    {
      "text": "哥哥把弟弟帶來學校。",
      "pinyin": "Gēge bǎ dìdi dài lái xuéxiào.",
      "pinyin_numeric": "ge1ge ba3 di4di dai4 lai2 xue2xiao4.",
      "translation_en": "My older brother brought my younger brother to school.",
      "translation_ko": "형이 남동생을 학교로 데려왔어요."
    },
    {
      "text": "請你把那杯水帶去教室。",
      "pinyin": "Qǐng nǐ bǎ nà bēi shuǐ dài qù jiàoshì.",
      "pinyin_numeric": "qing3 ni3 ba3 na4 bei1 shui3 dai4 qu4 jiao4shi4.",
      "translation_en": "Please take that glass of water to the classroom.",
      "translation_ko": "그 물 한 잔을 교실로 가져가 주세요."
    }
  ]
}
